#!/usr/bin/env python3
from __future__ import annotations

import argparse
import json
import os
import subprocess
import sys
from pathlib import Path
from typing import Any


DIRTY_BUCKETS = [
    "taskScoped",
    "preExistingUnrelated",
    "adjacentFollowup",
    "generatedOrCache",
    "sensitiveOrConfig",
    "unknown",
]

RESIDUAL_BUCKETS = [bucket for bucket in DIRTY_BUCKETS if bucket != "taskScoped"]

RESIDUAL_ACTION_FIELDS = ("paths", "action", "rationale", "nextStep")

RUNTIME_PATTERNS = (
    "/src/mcp/",
    "/src/rpc/",
    "/server.",
    "/mcp/",
    "/mcps/",
    "/hooks/",
    "/launchd/",
    "/LaunchAgents/",
    "/dot_codex/",
    "/dot_claude/",
    "/config.toml",
    "/hooks.json",
    "/settings.json",
    "/package.json",
    "/package-lock.json",
    "/pyproject.toml",
)


def run(cmd: list[str], cwd: Path) -> subprocess.CompletedProcess[str]:
    return subprocess.run(cmd, cwd=cwd, capture_output=True, text=True, timeout=30)


def git_dirty_paths(repo: Path) -> list[str]:
    cp = run(["git", "status", "--porcelain=v1", "-z"], repo)
    if cp.returncode != 0:
        raise RuntimeError(f"{repo}: git status failed: {cp.stderr.strip()}")
    paths: list[str] = []
    fields = cp.stdout.split("\0")
    i = 0
    while i < len(fields):
        item = fields[i]
        i += 1
        if not item:
            continue
        status = item[:2]
        path = item[3:]
        if status[0] in {"R", "C"} and i < len(fields):
            old_path = fields[i]
            i += 1
            paths.extend([old_path, path])
        else:
            paths.append(path)
    return sorted(set(paths))


# --------------------------------------------------------------------------- #
# Typed closeout patterns
#
# A closeout pattern recognizes a known deterministic post-edit state and emits
# a typed diagnosis + an exact next command, instead of falling back to the
# generic dirty-state handoff packet. The first pattern is the dotfiles
# memory-sync lane (S-009 / ADR 012): after editing memory/*, agents snapshot to
# the `memory-sync` branch, which routinely leaves a dirty memory/ overlay or a
# confusing origin/main vs origin/memory-sync split. The states below map the
# overlay deterministically to "snapshot", "promote", "push", or "leave it".
# --------------------------------------------------------------------------- #

MEMORY_BRANCH = "memory-sync"


def _git(repo: Path, *args: str) -> tuple[int, str, str]:
    cp = run(["git", *args], repo)
    return cp.returncode, cp.stdout.strip(), cp.stderr.strip()


def ref_exists(repo: Path, ref: str) -> bool:
    rc, _, _ = _git(repo, "rev-parse", "--verify", "--quiet", f"{ref}^{{commit}}")
    return rc == 0


def is_dotfiles_memory_repo(repo: Path) -> bool:
    """Recognize the dotfiles memory-sync repo by contents, not by absolute path.

    Definitive marker: the repo ships the memory-sync snapshot script. Fallback:
    a ``memory/MEMORY.md`` store plus a ``memory-sync`` ref (local or origin).
    """
    if not (repo / "memory").is_dir():
        return False
    if (repo / "home" / "dot_local" / "bin" / "executable_dotfiles-memory-snapshot").exists():
        return True
    if (repo / "memory" / "MEMORY.md").exists() and (
        ref_exists(repo, "refs/heads/memory-sync")
        or ref_exists(repo, "refs/remotes/origin/memory-sync")
    ):
        return True
    return False


def _mid_operation(repo: Path) -> bool:
    for marker in ("MERGE_HEAD", "rebase-merge", "rebase-apply"):
        rc, out, _ = _git(repo, "rev-parse", "--git-path", marker)
        if rc != 0 or not out:
            continue
        path = Path(out) if os.path.isabs(out) else (repo / out)
        if path.exists():
            return True
    return False


def _is_ancestor(repo: Path, ancestor: str, descendant: str) -> bool:
    rc, _, _ = _git(repo, "merge-base", "--is-ancestor", ancestor, descendant)
    return rc == 0


def _count(repo: Path, rev_range: str) -> int:
    rc, out, _ = _git(repo, "rev-list", "--count", rev_range)
    if rc != 0 or not out:
        return 0
    try:
        return int(out)
    except ValueError:
        return 0


def _name_status(repo: Path, base: str, src: str) -> list[dict[str, str]]:
    rc, out, _ = _git(repo, "diff", "--name-status", f"{base}..{src}", "--", "memory")
    if rc != 0 or not out:
        return []
    entries: list[dict[str, str]] = []
    for line in out.splitlines():
        parts = line.split("\t")
        if len(parts) < 2:
            continue
        entries.append({"status": parts[0], "path": parts[-1]})
    return entries


def _has_uncommitted_memory_edits(repo: Path, capture_ref: str | None, memory_dirty: list[str]) -> bool:
    if not memory_dirty:
        return False
    rc, out, _ = _git(repo, "ls-files", "-o", "--exclude-standard", "--", "memory")
    if rc == 0 and out:
        return True
    if capture_ref is None:
        return True
    rc, out, _ = _git(repo, "diff", "--name-only", capture_ref, "--", "memory")
    return bool(out)


def diagnose_memory_sync(repo: Path, dirty_paths: list[str]) -> dict[str, Any]:
    """Classify the dotfiles memory-sync closeout state from local git refs.

    Read-only and network-free: origin/* refs reflect the last fetch. States:
    clean, overlay-expected, needs-snapshot, snapshot-needs-push,
    snapshot-pushed-needs-promotion, conflict-or-ambiguous.
    """
    memory_dirty = [p for p in dirty_paths if p == "memory" or p.startswith("memory/")]
    has_local = ref_exists(repo, "refs/heads/memory-sync")
    has_origin = ref_exists(repo, "refs/remotes/origin/memory-sync")
    has_origin_main = ref_exists(repo, "refs/remotes/origin/main")
    has_local_main = ref_exists(repo, "refs/heads/main")
    rc, head, _ = _git(repo, "symbolic-ref", "--short", "-q", "HEAD")
    head = head if rc == 0 and head else None

    evidence: dict[str, Any] = {
        "head": head,
        "memoryDirtyPaths": memory_dirty,
        "localMemorySync": has_local,
        "originMemorySync": has_origin,
        "originMain": has_origin_main,
        "originFetched": False,
    }
    notes = [
        "origin/* refs reflect the last fetch; run `dotfiles memory diagnose --fetch` for an authoritative check.",
    ]

    def result(state: str, ok: bool, summary: str, action: dict[str, str] | None) -> dict[str, Any]:
        return {
            "diagnosis": {
                "pattern": "dotfiles-memory-sync",
                "state": state,
                "ok": ok,
                "summary": summary,
                "recommendedAction": action,
                "evidence": evidence,
                "notes": notes,
            },
            "coveredPaths": memory_dirty,
        }

    if _mid_operation(repo):
        return result(
            "conflict-or-ambiguous",
            False,
            "repository is mid-rebase or mid-merge; the memory-sync state cannot be classified safely",
            {
                "name": "resolve",
                "command": "git status",
                "rationale": "Finish or abort the in-progress git operation, then re-run the closeout check.",
            },
        )

    capture_ref = (
        "refs/heads/memory-sync"
        if has_local
        else ("refs/remotes/origin/memory-sync" if has_origin else None)
    )

    if _has_uncommitted_memory_edits(repo, capture_ref, memory_dirty):
        return result(
            "needs-snapshot",
            False,
            "memory/ has edits not yet captured on the memory-sync snapshot branch",
            {
                "name": "snapshot",
                "command": "dotfiles memory snapshot",
                "rationale": "Snapshot memory/ onto memory-sync via an isolated index; it never commits memory to the current branch.",
            },
        )

    if capture_ref is None:
        return result(
            "clean",

