def load_packet(path: Path | None) -> dict[str, Any]:
    if path is None:
        return {}
    try:
        data = json.loads(path.read_text())
    except Exception as exc:
        raise RuntimeError(f"failed to read closeout packet {path}: {exc}") from exc
    if not isinstance(data, dict):
        raise RuntimeError(f"closeout packet {path} must be a JSON object")
    return data


def packet_dirty_entries(packet: dict[str, Any]) -> list[dict[str, Any]]:
    entries = packet.get("dirtyState", [])
    if entries is None:
        return []
    if not isinstance(entries, list) or not all(isinstance(entry, dict) for entry in entries):
        raise RuntimeError("packet.dirtyState must be a list of objects")
    return entries


def paths_covered(entry: dict[str, Any]) -> set[str]:
    covered: set[str] = set()
    for bucket in DIRTY_BUCKETS:
        value = entry.get(bucket, [])
        if value is None:
            value = []
        if not isinstance(value, list) or not all(isinstance(item, str) for item in value):
            raise RuntimeError(f"dirtyState.{bucket} must be a list of paths")
        covered.update(value)
    return covered


def validate_dirty_packet(repo: Path, dirty_paths: list[str], packet: dict[str, Any]) -> list[str]:
    if not dirty_paths:
        return []
    repo_str = str(repo)
    entries = [
        entry
        for entry in packet_dirty_entries(packet)
        if entry.get("repo") in {repo_str, str(repo.resolve())}
    ]
    if not entries:
        return [f"{repo}: dirty-state handoff packet required for {len(dirty_paths)} dirty path(s)"]
    errors: list[str] = []
    entry = entries[0]
    covered = paths_covered(entry)
    missing = sorted(set(dirty_paths) - covered)
    if missing:
        errors.append(f"{repo}: dirty-state packet does not classify: {', '.join(missing)}")
    unknown = entry.get("unknown") or []
    if unknown and not entry.get("nextQuestion"):
        errors.append(f"{repo}: unknown dirty paths require nextQuestion")
    required_keys = {"blocksCommit", "nextQuestion"}
    missing_keys = sorted(required_keys - set(entry))
    if missing_keys:
        errors.append(f"{repo}: dirty-state packet missing keys: {', '.join(missing_keys)}")
    errors.extend(validate_residual_actions(repo, entry))
    return errors


def validate_residual_actions(repo: Path, entry: dict[str, Any]) -> list[str]:
    residual_paths: set[str] = set()
    for bucket in RESIDUAL_BUCKETS:
        residual_paths.update(entry.get(bucket) or [])
    if not residual_paths:
        return []
    actions = entry.get("residualActions")
    if not isinstance(actions, list) or not actions:
        return [
            f"{repo}: residual dirty paths require residualActions entries with "
            f"paths/action/rationale/nextStep covering: {', '.join(sorted(residual_paths))}"
        ]
    errors: list[str] = []
    covered: set[str] = set()
    for action in actions:
        if not isinstance(action, dict):
            errors.append(f"{repo}: residualActions entries must be objects")
            continue
        missing_fields = [field for field in RESIDUAL_ACTION_FIELDS if not action.get(field)]
        if missing_fields:
            errors.append(f"{repo}: residualActions entry missing {', '.join(missing_fields)}")
        paths = action.get("paths")
        if isinstance(paths, list):
            covered.update(item for item in paths if isinstance(item, str))
    missing_residual = sorted(residual_paths - covered)
    if missing_residual:
        errors.append(f"{repo}: residualActions does not cover: {', '.join(missing_residual)}")
    return errors


